function App() {
  const canvasRef = useRef<{ getDataUrl: () => string | null }>(null);
  const [canvasConfig, setCanvasConfig] = useState<CanvasConfig>({
    width: 512,
    height: 512,
  });
  const [aiConfig, setAIConfig] = useState<AIConfig>({
    prompt: 'a beautiful landscape',
    negative_prompt: '',
    initial_latent: 'None',
    cfg: 2.0,
    background_threshold: 0.8,
    image_size: 'square_hd',
    num_images: 1,
  });
  const [results, setResults] = useState<GeneratedResult[]>([]);
  const [generating, setGenerating] = useState(false);

  const handleGenerate = async () => {
    if (!canvasRef.current) {
      message.error('Canvas not ready');
      return;
    }

    const dataUrl = canvasRef.current.getDataUrl();
    if (!dataUrl) {
      message.error('Failed to get canvas content');
      return;
    }

    try {
      setGenerating(true);

      const result = await generateWithIcLightV2({
        image_url: dataUrl,
        prompt: aiConfig.prompt,
        negative_prompt: aiConfig.negative_prompt,
        initial_latent: aiConfig.initial_latent as 'None' | 'Left' | 'Right' | 'Top' | 'Bottom',
        cfg: aiConfig.cfg,
        background_threshold: aiConfig.background_threshold,
        image_size: aiConfig.image_size,
        num_images: aiConfig.num_images,
      });

      if (result.images) {
        setResults(
          result.images.map((img) => ({
            imageUrl: img.url,
            timestamp: new Date().toISOString(),
          }))
        );
        message.success('Generated successfully!');
      }
    } catch (error) {
      console.error('Generation failed:', error);
      message.error('Failed to generate image');
    } finally {
      setGenerating(false);
    }
  };

  return (
    <Layout>
      <Sider width={400} theme="light">
        <ConfigPanel
          onAIConfigChange={setAIConfig}
          onCanvasConfigChange={setCanvasConfig}
          onGenerate={handleGenerate}
          generating={generating}
        />
      </Sider>
      <Content>
        <Canvas
          ref={canvasRef}
          config={canvasConfig}
        />
      </Content>
      <Sider width={400} theme="light">
        <ResultPanel results={results} />
      </Sider>
    </Layout>
  );
}

