generateWithIcLightV2 = async (input: IcLightV2Input): Promise<IcLightV2Output> => {
  console.log('Calling FAL iclight-v2 with input:', {
    ...input,
    image_url: input.image_url.substring(0, 100) + '...' // 只显示 URL 的开头部分
  });

  try {
    const result = await fal.subscribe('fal-ai/iclight-v2', {
      input: {
        ...input,
        num_inference_steps: 30,
        lowres_denoise: 0.98,
        highres_denoise: 0.95,
        hr_downscale: 0.5,
        enable_safety_checker: true,
        output_format: 'jpeg',
        enable_hr_fix: true,
      },
    }) as IcLightV2Output;  // 添加类型断言

    console.log('FAL API response:', {
      seed: result.seed,
      imageCount: result.images?.length || 0,
      firstImageUrl: result.images?.[0]?.url
    });

    return result;
  } catch (error) {
    console.error('FAL API error:', error);
    throw error;
  }
}

